programs._raw:
{
  "name": "Louisiana Long Term–Personal Care Services (LT-PCS) Program",
  "eligibility": {
    "age": "65+ for elderly or 21+ for disabled[1][5]",
    "income_limits": "Must meet Louisiana Medicaid ABD financial eligibility (income and asset limits vary by marital status and program; for single Nursing Home Medicaid applicant in 2026: income limit not specified in sources, asset limit $2,000 in countable assets)[3]",
    "asset_limits": "Countable assets limited to $2,000 for single applicant (includes bank accounts, retirement accounts, stocks, bonds, CDs, cash, and other easily convertible assets); home exempt if applicant lives there or intends to return with home equity ≤$752,000 in 2026, or if spouse/minor child (under 21)/blind or disabled child lives there[1][3]",
    "other_requirements": [
      "Louisiana resident",
      "Enrolled in Medicaid (ABD category)",
      "Require Nursing Facility Level of Care (NFLOC), determined by Level of Care Eligibility Tool (LOCET) assessing needs in Activities of Daily Living (ADLs) like transferring, mobility, eating, toileting, hygiene, bathing[1][2][3]",
      "Meet one of: reside in nursing home and able to relocate to community with assistance; anticipated to need nursing home within 120 days; main caregiver disabled or aged 70+[1]",
      "Able to direct own care or have representative (no support coordination provided)[1]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Long-term personal care services and supports in own home or loved one's home to assist with daily living activities (ADLs) for those requiring Nursing Facility Level of Care; provided per approved service plan via uniform interRAI home care assessment determining resource allocation and ADL support needs[1][2][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Requests accepted from Medicaid participant, legally responsible individual, or designated representative[2]"
    ],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": [
      "Level of Care Eligibility Tool (LOCET) for functional screening[1][2]",
      "Uniform interRAI home care assessment tool for full assessment[2]"
    ],
    "documents": [
      "Documentation for Medicaid enrollment",
      "Proof of residency, age/disability, financials (assets/income), NFLOC via LOCET and interRAI assessment[1][2][3]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": null
  },
  "official_source": "https://ldh.la.gov/assets/docs/OAAS/publications/FactSheets/LTPCS-Fact-Sheet.pdf[5]",
  "gotchas": [
    "Must already receive Medicaid benefits (ABD); not a standalone program[1][3][5]",
    "No support coordination included—applicant must self-direct care or have representative[1]",
    "Home equity limit $752,000 in 2026 applies even if exempt[1]",
    "Specific NFLOC pathways required via LOCET (e.g., ADL assistance needs)[1][2][3]",
    "Requests only from participant, legal responsible party, or designated rep[2]"
  ],
  "data_shape_notes": "Tied to Medicaid ABD enrollment with NFLOC via LOCET/interRAI tools; services per individualized plan based on ADL score; multiple eligibility pathways (nursing home transition, imminent need, elderly/disabled caregiver)"
}
